'use client'
import { cn, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import type { HTMLAttributes } from 'react'
import styles from './spinner.module.css'

export interface SpinnerProps extends HTMLAttributes<HTMLSpanElement> {
  size?: 'sm' | 'md' | 'lg'
  label?: string
}

export function Spinner({ size = 'md', label, className, ...props }: SpinnerProps) {
  useSignals()
  const resolvedLabel = label ?? t(builtin.spinner.label)
  return (
    <span
      role="status"
      aria-label={resolvedLabel}
      data-size={size}
      className={cn(styles['spinner'], className as string | undefined)}
      {...props}
    />
  )
}

@layer cascivo.component {
  .spinner {
    display: inline-block;
    box-sizing: border-box;
    border-style: solid;
    border-color: currentColor;
    border-block-start-color: transparent;
    border-radius: var(--cascivo-radius-full);
    animation: cascade-spin 0.6s linear infinite;

    &[data-size='sm'] {
      width: 1rem;
      height: 1rem;
      border-width: 2px;
    }

    &[data-size='md'] {
      width: 1.5rem;
      height: 1.5rem;
      border-width: 2px;
    }

    &[data-size='lg'] {
      width: 2rem;
      height: 2rem;
      border-width: 3px;
    }
  }

  @keyframes cascade-spin {
    to {
      transform: rotate(360deg);
    }
  }

  @media (prefers-reduced-motion: reduce) {
    .spinner {
      animation-duration: 1.5s;
    }
  }
}
